class NetworkLogger {
    static let shared = NetworkLogger()
    
    private init() {}
    
    func logRequest(_ request: URLRequest, userId: String?, authToken: String?) {
        guard let url = request.url else { return }
        
        NSLog("[NETWORK] Outgoing Request to: %@", url.absoluteString)
        print("[NETWORK] Request Details:")
        print("  URL: \(url.absoluteString)")
        print("  Method: \(request.httpMethod ?? "GET")")
        
        if let userId = userId {
            print("  User ID: \(userId)")
        }
        
        if let authToken = authToken {
            print("  Auth Token: \(authToken)")
        }
        
        if let headers = request.allHTTPHeaderFields {
            print("  Headers: \(headers)")
        }
        
        if let body = request.httpBody, let bodyString = String(data: body, encoding: .utf8) {
            print("  Body: \(bodyString)")
        }
        
        print("  Timestamp: \(Date())")
    }
    
    func logResponse(_ response: URLResponse?, data: Data?, error: Error?, userId: String?) {
        if let httpResponse = response as? HTTPURLResponse {
            NSLog("[NETWORK] Response Status: %d from %@", httpResponse.statusCode, httpResponse.url?.absoluteString ?? "Unknown")
            print("[NETWORK] Response Details:")
            print("  URL: \(httpResponse.url?.absoluteString ?? "Unknown")")
            print("  Status Code: \(httpResponse.statusCode)")
            print("  Headers: \(httpResponse.allHeaderFields)")
            
            if let userId = userId {
                print("  User ID: \(userId)")
            }
            
            if let data = data, let responseString = String(data: data, encoding: .utf8) {
                print("  Response Data: \(responseString)")
            }
        }
        
        if let error = error {
            NSLog("[NETWORK] Error: %@, User: %@", error.localizedDescription, userId ?? "N/A")
            print("  Error: \(error)")
            print("  Error Description: \(error.localizedDescription)")
        }
        
        print("  Timestamp: \(Date())")
    }
}

