class CrashReporter {
    static let shared = CrashReporter()
    
    private init() {}
    
    func logCrash(error: Error, userId: String?, email: String?, token: String?, context: String, userInfo: [String: Any]?) {
        NSLog("[CRASH] Application crash - User: %@, Context: %@", userId ?? "N/A", context)
        print("[CRASH] Crash Report:")
        print("  Error: \(error)")
        print("  Error Description: \(error.localizedDescription)")
        if let userId = userId {
            print("  User ID: \(userId)")
        }
        if let email = email {
            print("  Email: \(email)")
        }
        if let token = token {
            print("  Auth Token: \(token)")
        }
        print("  Context: \(context)")
        if let userInfo = userInfo {
            print("  User Info: \(userInfo)")
        }
        print("  Stack Trace: \(Thread.callStackSymbols)")
        print("  Timestamp: \(Date())")
    }
    
    func logException(exception: NSException, userId: String?, email: String?) {
        NSLog("[EXCEPTION] %@ - User: %@", exception.name.rawValue, userId ?? "N/A")
        print("[EXCEPTION] Exception Caught:")
        print("  Name: \(exception.name.rawValue)")
        print("  Reason: \(exception.reason ?? "Unknown")")
        if let userId = userId {
            print("  User ID: \(userId)")
        }
        if let email = email {
            print("  Email: \(email)")
        }
        print("  Call Stack: \(exception.callStackSymbols)")
        print("  Timestamp: \(Date())")
    }
